.addOrEdit {
  display: flex;
  flex-direction: column;
  // border: 1px solid red;
  .addOrEdit-top {
    display: flex;
    gap: 10px;
    height: calc(100vh - @header-height - 184px);
    overflow: hidden;
    .addOrEdit-left {
      width: 100%;
      padding: 20px 15px;
      overflow-y: auto;
      min-height: 0;
      .addOrEdit-title-id {
        display: flex;
        align-items: center;
        gap: 8px;
        border-radius: 8px;
        padding: 4px 12px;
        background-color: #f7f8fa;
        // border: 1px solid red;
        .incident-id-bar {
          &__label {
            font-weight: 400;
            font-size: 14px;
            line-height: 22px;
            color: #4e5969;
          }
          &__related-value {
            color: #30647f;
            cursor: pointer;
            &:hover {
              text-decoration: underline;
            }
          }
          &__-value {
            font-weight: 400;
            font-size: 14px;
            line-height: 22px;
            color: #1d2129;
          }
        }
      }

      .incidentDom {
        display: flex;
        width: 240px;
        height: 36px;
        align-items: center;
        cursor: pointer;
        background-color: #f7f8fa;
        .incidentDom-item {
          width: 114px;
          height: 28px;
          color: #86909c;
          display: flex;
          justify-content: center;
          align-items: center;
        }
        .incidentDom-item.active {
          background-color: #30647f;
          color: #ffffff;
          border-radius: 6px;
        }
      }

      .incident-dynamic-table-wrap {
        margin-bottom: 8px;
      }

      .incident-dynamic-table-label {
        font-size: 14px;
        color: var(--color-text-1);
        margin-bottom: 8px;
        line-height: 1.5715;

        &--required::before {
          content: '*';
          color: rgb(var(--red-6));
          margin-right: 4px;
          font-size: 20px;
          line-height: 1;
          font-weight: 550;
          vertical-align: middle;
          body[dir='ltr'] & {
            padding-left: 3px;
          }
          body[dir='rtl'] & {
            padding-right: 3px;
          }
        }
      }

      .incident-dynamic-table {
        width: 100%;
        border-collapse: separate;
        border-spacing: 0;
        border: 1px solid #e5e6eb;
        border-radius: 8px;
        overflow: hidden;
        background: #fff;
        // border: 1px solid red;

        thead tr {
          background: #f7f8fa;
        }

        th {
          padding: 10px 12px;
          text-align: left;
          font-weight: 500;
          font-size: 13px;
          color: #1d2129;
          border-bottom: 1px solid #e5e6eb;
          .ant-form-item-required {
            color: rgb(var(--danger-6));
            margin-right: 4px;
            font-size: 20px;
            align-items: center;
          }
        }

        td {
          padding: 8px 12px;
          vertical-align: middle;
          border-bottom: 1px solid #e5e6eb;
          background: #fff;

          .formblink-enter-done {
            display: none;
          }
        }

        /* 动态表格内字段垂直居中 */
        .incident-dynamic-table__cell-item {
          margin-bottom: 0;
          display: flex;
          align-items: center;
          min-height: 36px;
        }

        .incident-dynamic-table__cell-item [class*='form-item-control'] {
          width: 100%;
          display: flex;
          align-items: center;
        }

        .arco-form-item {
          margin-bottom: 0;
        }

        .arco-form-item-message {
          display: none;
        }
        .incident-dynamic-table__cell-item .arco-form-item-message,
        .incident-dynamic-table__cell-item .arco-form-item-help,
        .incident-dynamic-table__cell-item .arco-form-item-extra,
        .incident-dynamic-table__cell-item [class*='form-item-message'],
        .incident-dynamic-table__cell-item [class*='form-item-help'] {
          display: none !important;
          min-height: 0 !important;
          margin: 0 !important;
        }

        tbody tr:last-child td {
          border-bottom: none;
        }

        .arco-input,
        .arco-textarea,
        .arco-select-view {
