// ─── Floor selector ────────────────────────────────────────────────────────────
const FLOOR_OPTIONS = [
  'G',
  'M',
  '1',
  '2',
  '3',
  '4',
  '5',
  '6',
  'RF',
  'P1',
  'P2',
  'P3',
]

const FloorSelector: FC<{
  value?: string[]
  onChange?: (val: string[]) => void
  disabled?: boolean
}> = ({ value = [], onChange, disabled = false }) => {
  const toggle = (floor: string) => {
    if (disabled) return
    const next = value.includes(floor)
      ? value.filter((f) => f !== floor)
      : [...value, floor]
    onChange?.(next)
  }
  return (
    <div
      className={`floor-selector${disabled ? ' floor-selector--disabled' : ''}`}
    >
      {FLOOR_OPTIONS.map((floor) => (
        <button
          key={floor}
          type='button'
          disabled={disabled}
          className={`floor-btn${value.includes(floor) ? ' selected' : ''}`}
          onClick={() => toggle(floor)}
        >
          {floor}
        </button>
      ))}
    </div>
  )
}

// ─── Yes / No toggle ───────────────────────────────────────────────────────────
const YES_NO_OPTIONS = [
  { label: 'Yes', value: 1 },
  { label: 'No', value: 2 },
] as const

type YesNoToggleProps = { value?: number; onChange?: (v: number) => void }
const YesNoToggle: FC<YesNoToggleProps> = ({ value, onChange }) => (
  <div className='incidentDom'>
    {YES_NO_OPTIONS.map((item) => (
      <div
        key={item.value}
        role='button'
        tabIndex={0}
        className={classNames('incidentDom-item', {
          active: value === item.value,
        })}
        onClick={() => onChange?.(item.value)}
        onKeyDown={(e) => {
          if (e.key === 'Enter' || e.key === ' ') {
            e.preventDefault()
            onChange?.(item.value)
          }
        }}
      >
        {item.label}
      </div>
    ))}
  </div>
)

