// ─── Main component ────────────────────────────────────────────────────────────
const AddOrEdit = ({ current, userList, setShowStatus }) => {
  const { t } = useTranslation(['common', 'incidentReport'])
  const { id } = useParams()
  const [form] = Form.useForm()
  const navigate = useNavigate()
  const [orgData, setOrgData] = useState<any[]>([])
  const [infoData, setInfoData] = useState<any>()
  const [approveLog, setApproveLog] = useState<any>([])
  const [approveFlag, setApproveFlag] = useState<number>(0)
  const [fileList, setFileList] = useState<any>()
  const addEmployeeRef = useRef<(defaultValue?: any) => void>(null)
  const addPropertyRef = useRef<(defaultValue?: any) => void>(null)

  // ── UI toggle state ──
  // const [emergencyLocation, setEmergencyLocation] = useState<any>()
  const emergencyLocation = Form.useWatch('locationType', form)
  const externalPartyInvolved = Form.useWatch('externalPartyInvolved', form)
  const [partyChecks, setPartyChecks] = useState<Record<PartyKey, boolean>>({
    police: false,
    ambulance: false,
    fireDepartment: false,
    others: false,
  })
  const [impactChecks, setImpactChecks] = useState({
    employee: false,
    property: false,
    other: false,
  })

  // ── API ──
  const { run: approvalDetail } = useRequest(getApprovalDetail, {
    manual: true,
    onSuccess: (res: any) => {
      setApproveLog(res?.approveList || [])
      setApproveFlag(res?.approveFlag)
    },
  })

  const { run: getIncidentReportDetail, loading: detailLoading } = useRequest(
    incidentReportDetail,
    {
      manual: true,
      onSuccess: (res: any) => {
        setInfoData(res)
        setShowStatus(res?.status)
      },
    },
  )

  const { run: runIncidentReportSubmit } = useRequest(incidentReportSubmit, {
    manual: true,
    onSuccess: () => {
      navigate(`/incident-report/incident-report-management/addOrEdit/3/${id}`)
    },
  })

  const { run: saveDetail, loading: saveDetailLoading } = useRequest(
    saveDetailIncidentReport,
    {
      manual: true,
      onSuccess: () => {
        runIncidentReportSubmit({ incidentReportId: id })
      },
    },
  )

  const { run: saveOnly, loading: saveOnlyLoading } = useRequest(
    saveDetailIncidentReport,
    {
      manual: true,
      onSuccess: () => {
        Message.success(t('incidentReport:messages.saveSuccess') || 'Saved')
      },
    },
  )

  // ── Init ──
  useEffect(() => {
    if (id) {
      getIncidentReportDetail({ incidentReportId: id })
      approvalDetail({ incidentReportId: id })
      fetchOrgTree()
    }
  }, [id])

  useEffect(() => {
    if (!infoData) return
    // Parse externalParties[] → partyChecks + flat form fields
    const partyFormValues: any = {}
    if (infoData.externalParties?.length > 0) {
      const newPartyChecks = {
        police: false,
        ambulance: false,
        fireDepartment: false,
        others: false,
      }
      infoData.externalParties.forEach((p: any) => {
        if (p.partyType === 1) {
          newPartyChecks.police = true
          partyFormValues.policeResponseDetailsAr = p.responseDetailsAr
          partyFormValues.policeResponseDetails = p.responseDetailsEn
          partyFormValues.policeAttachments = p.attachmentList
        } else if (p.partyType === 2) {
          newPartyChecks.ambulance = true
          partyFormValues.ambulanceResponseDetailsAr = p.responseDetailsAr
          partyFormValues.ambulanceResponseDetails = p.responseDetailsEn
          partyFormValues.ambulanceAttachments = p.attachmentList
        } else if (p.partyType === 3) {
          newPartyChecks.fireDepartment = true
          partyFormValues.fireDeptResponseDetailsAr = p.responseDetailsAr
          partyFormValues.fireDeptResponseDetails = p.responseDetailsEn
          partyFormValues.fireDeptAttachments = p.attachmentList
        } else if (p.partyType === 4) {
          newPartyChecks.others = true
          partyFormValues.othersResponseDetailsAr = p.responseDetailsAr
          partyFormValues.othersResponseDetails = p.responseDetailsEn
          partyFormValues.othersAttachments = p.attachmentList
        }
      })
      setPartyChecks(newPartyChecks)
    }

    form.setFieldsValue({
      incidentDate: infoData.incidentDate
        ? `${infoData.incidentDate}`
        : undefined,
      locationType: infoData?.locationType,
      floors: infoData?.floors,
      incidentDetailsAr: infoData.incidentDetailsAr,
      incidentDetails: infoData.incidentDetails,
      actionsTakenAr: infoData.actionsTakenAr,
      actionsTaken: infoData.actionsTaken,
      attachments: infoData.attachmentList,
      externalPartyInvolved: infoData.externalPartyInvolved,
      ...partyFormValues,
      incidentReportDetailEmployeeSaveRequests:
        infoData.employees?.length > 0
          ? infoData.employees
          : [emptyEmployeeRow()],
      incidentReportDetailPropertySaveRequests:
        infoData.properties?.length > 0
          ? infoData.properties
          : [emptyPropertyRow()],
      otherImpactAr: infoData.otherImpactAr,
      otherImpact: infoData.otherImpact,
      issues:
        infoData.issues?.length > 0
          ? infoData.issues.map((issue: any) => ({
              id: issue.id,
              notesRemarksAr: issue.notesRemarksAr,
              notesRemarksEn: issue.notesRemarksEn,
              attachmentList: issue.attachmentList,
              correctiveActionAr: issue.correctiveActionAr,
              correctiveActionEn: issue.correctiveActionEn,
              responsibleOrgId: issue.responsibleOrgId,
              targetClosureDate: issue.targetClosureDate,
            }))
          : [],
    })

    if (infoData.employeeImpacted === 1 || infoData.employees?.length > 0)
      setImpactChecks((p) => ({ ...p, employee: true }))
    if (infoData.propertyImpacted === 1 || infoData.properties?.length > 0)
      setImpactChecks((p) => ({ ...p, property: true }))
    if (
      infoData.otherImpacted === 1 ||
      infoData.otherImpactAr ||
      infoData.otherImpact
    )
      setImpactChecks((p) => ({ ...p, other: true }))
  }, [infoData])

  // ── Collect payload ──
  const collectPayload = (data: any) => ({
    incidentReportId: id,
    incidentDate: data.incidentDate ? `${data.incidentDate}` : undefined,
    locationSystem: data.locationSystem,
    locationSystemAr: data.locationSystemAr,
    incidentDetailsAr: data.incidentDetailsAr,
    incidentDetails: data.incidentDetails,
    actionsTakenAr: data.actionsTakenAr,
    actionsTaken: data.actionsTaken,
    attachmentList: data.attachments,
    externalPartyInvolved: data.externalPartyInvolved,
    externalParties:
      data.externalPartyInvolved === 1
        ? [
            ...(partyChecks.police
              ? [
                  {
                    partyType: 1,
                    responseDetailsEn: data.policeResponseDetails,
                    responseDetailsAr: data.policeResponseDetailsAr,
                    attachmentList: data.policeAttachments,
                  },
                ]
              : []),
            ...(partyChecks.ambulance
              ? [
                  {
                    partyType: 2,
                    responseDetailsEn: data.ambulanceResponseDetails,
                    responseDetailsAr: data.ambulanceResponseDetailsAr,
                    attachmentList: data.ambulanceAttachments,
                  },
                ]
              : []),
            ...(partyChecks.fireDepartment
              ? [
                  {
                    partyType: 3,
                    responseDetailsEn: data.fireDeptResponseDetails,
                    responseDetailsAr: data.fireDeptResponseDetailsAr,
                    attachmentList: data.fireDeptAttachments,
                  },
                ]
              : []),
            ...(partyChecks.others
              ? [
                  {
                    partyType: 4,
                    responseDetailsEn: data.othersResponseDetails,
                    responseDetailsAr: data.othersResponseDetailsAr,
                    attachmentList: data.othersAttachments,
                  },
                ]
              : []),
          ]
        : [],
    employeeImpacted: impactChecks.employee ? 1 : 0,
    propertyImpacted: impactChecks.property ? 1 : 0,
    otherImpacted: impactChecks.other ? 1 : 0,
    incidentReportDetailEmployeeSaveRequests: impactChecks.employee
      ? data.incidentReportDetailEmployeeSaveRequests
      : [],
    incidentReportDetailPropertySaveRequests: impactChecks.property
      ? data.incidentReportDetailPropertySaveRequests
      : [],
    otherImpactAr: impactChecks.other ? data.otherImpactAr : undefined,
    otherImpact: impactChecks.other ? data.otherImpact : undefined,
    issues: (data.issues || []).map((issue: any) => ({
      id: issue.id,
      notesRemarksAr: issue.notesRemarksAr,
      notesRemarksEn: issue.notesRemarksEn,
      correctiveActionAr: issue.correctiveActionAr,
      correctiveActionEn: issue.correctiveActionEn,
      responsibleOrgId: issue.responsibleOrgId,
      targetClosureDate: issue.targetClosureDate,
      attachmentList: issue.attachmentList,
    })),
  })

  const handelSubmit = () => {
    form.validate().then(() => {
      saveDetail(collectPayload(form.getFieldsValue()))
    })
  }

  const handleSave = () => {
    const data = collectPayload(form.getFieldsValue())
    saveOnly(collectPayload(form.getFieldsValue()))
  }

  const handelCancel = () => {
    navigate('/incident-report/incident-report-management')
  }

  const onFileListChange = (value) => {
    setFileList(value.map((item) => item?.response))
  }

  // ── Party block renderer ──
  const renderPartyBlock = (key: PartyKey) => {
    const { icon, fieldPrefix } = PARTY_META[key]
    const checked = partyChecks[key]
    const labelKey = `incidentReport:form.${key === 'fireDepartment' ? 'fireDepartment' : key}`
    console.log('key', key)
    // const isBor = key != 'ambulance' || key != 'fireDepartment'
    return (
      <div key={key} className={`party-block party-block-${key}`}>
