  // 关联了应急响应(relatedEmergencyCode 存在)时,事件时间/地点/楼层不可编辑
  const relatedEmergencyLocked = Boolean(infoData?.relatedEmergencyCode)
  return (
    <Spin loading={detailLoading} block className='addOrEdit-spin'>
