                <div className='incident-id-bar'>
                  <span className='incident-id-bar__label'>
                    {t('incidentReport:incidentId')}
                  </span>
                  <span className='incident-id-bar__value'>
                    {infoData.incidentCode}
                  </span>
                </div>
              )}
              {infoData?.relatedEmergencyCode && (
                <div className='incident-id-bar'>
                  <span className='incident-id-bar__label'>
                    {t('incidentReport:relatedEmergencyResponse')}
                  </span>
                  <span
                    className='incident-id-bar__related-value'
                    onClick={() =>
                      navigate(
                        `/emergency-response/emergency-response-activation/detail/${infoData?.relatedEmergencyId}/active`,
                      )
                    }
                  >
                    {infoData.relatedEmergencyCode}
                  </span>
                </div>
              )}
            </div>

            <Form
              form={form}
              layout='vertical'
              initialValues={{
                incidentReportDetailEmployeeSaveRequests: [emptyEmployeeRow()],
                incidentReportDetailPropertySaveRequests: [emptyPropertyRow()],
                issues: [],
              }}
            >
              {/* ─── BASIC INFORMATION ─── */}
              <div className='section-header'>
                <span>{t('incidentReport:section.basicInformation')}</span>
              </div>
              <Row gutter={24}>
                <Col span={12}>
                  <FormItem
                    label={t('incidentReport:columns.incidentDateTime')}
                    field='incidentDate'
                    rules={[
                      { required: true, message: t('common:pleaseSelect') },
                    ]}
                  >
                    <DatePicker
                      format='DD/MM/YYYY HH:mm'
                      showTime
                      style={{ width: '100%' }}
                      disabled={relatedEmergencyLocked}
                      icons={{ inputSuffix: <IconCalendar /> }}
                    />
                  </FormItem>
                </Col>
                <Col span={12}>
                  <FormItem
                    label={t('incidentReport:form.emergencyLocation')}
                    field='locationType'
                    rules={[
                      { required: true, message: t('common:pleaseSelect') },
                    ]}
                  >
                    <RadioGroup
                      disabled={relatedEmergencyLocked}
                      onChange={(val) => {
                        if (val !== EmergencyLocation.InsideTheBuilding)
                          form.setFieldValue('floorOfEmergency', [])
                      }}
                    >
                      <Radio value={EmergencyLocation.OutOfTheBuilding}>
                        {t('incidentReport:form.outOfBuilding')}
                      </Radio>
                      <Radio value={EmergencyLocation.InsideTheBuilding}>
                        {t('incidentReport:form.insideBuilding')}
                      </Radio>
                    </RadioGroup>
                  </FormItem>
                </Col>
                {emergencyLocation === EmergencyLocation.InsideTheBuilding && (
                  <Col span={24}>
                    <FormItem
                      label={t('incidentReport:form.floorOfEmergency')}
                      field='floors'
                      rules={[
                        {
                          required: true,
                          validator: (val, cb) => {
                            if (!val || val.length === 0)
                              cb(t('common:pleaseSelect'))
                            else cb()
                          },
                        },
                      ]}
                    >
                      <FloorSelector disabled={relatedEmergencyLocked} />
                    </FormItem>
                  </Col>
                )}
                <Col span={12}>
                  <FormItem
                    label={t('incidentReport:form.incidentDetailsAr')}
                    field='incidentDetailsAr'
                    rules={[
                      { required: true, message: t('common:pleaseEnter') },
                    ]}
                  >
                    <TextArea
                      placeholder={t('common:pleaseEnter')}
                      maxLength={500}
                      showWordLimit
                    />
                  </FormItem>
                </Col>
                <Col span={12}>
                  <FormItem
                    label={t('incidentReport:form.incidentDetailsEn')}
                    field='incidentDetails'
                  >
                    <TextArea
                      placeholder={t('common:pleaseEnter')}
                      maxLength={500}
                      showWordLimit
                    />
                  </FormItem>
                </Col>
                <Col span={12}>
                  <FormItem
                    label={t('incidentReport:form.actionsTakenAr')}
                    field='actionsTakenAr'
                  >
                    <TextArea
                      placeholder={t('common:pleaseEnter')}
                      maxLength={500}
                      showWordLimit
                    />
                  </FormItem>
                </Col>
                <Col span={12}>
                  <FormItem
                    label={t('incidentReport:form.actionsTakenEn')}
                    field='actionsTaken'
                  >
                    <TextArea
                      placeholder={t('common:pleaseEnter')}
                      maxLength={500}
                      showWordLimit
                    />
                  </FormItem>
                </Col>
                <Col span={24}>
                  <FormItem
                    label={t('incidentReport:form.attachment')}
                    field='attachments'
                    initialValue={[]}
                  >
                    <IncidentAttachmentUpload
                      onFileListChange={onFileListChange}
                    />
                  </FormItem>
                </Col>
              </Row>

              {/* ─── EXTERNAL PARTY INVOLVED ─── */}
              <div className='section-header'>
                <span>{t('incidentReport:section.externalPartyInvolved')}</span>
              </div>
              <Row gutter={24}>
                <Col span={24}>
                  <FormItem
                    label={t('incidentReport:form.externalPartyInvolved')}
                    field='externalPartyInvolved'
                    rules={[
                      { required: true, message: t('common:pleaseSelect') },
                    ]}
                  >
                    <YesNoToggle />
                  </FormItem>
                </Col>
                {externalPartyInvolved === 1 && (
                  <Col span={24}>{PARTY_KEYS.map(renderPartyBlock)}</Col>
                )}
              </Row>

              {/* ─── IMPACT ─── */}
              <div className='section-header'>
                <span>{t('incidentReport:section.impact')}</span>
              </div>

              {/* Employee Impacted */}
              <div className='impact-block impact-block-employee'>
                <div
                  className={classNames('impact-block-header', {
                    'impact-block-header--checked': impactChecks.employee,
                  })}
                  onClick={() =>
                    setImpactChecks((p) => ({ ...p, employee: !p.employee }))
                  }
                >
                  <div className='employee-left'>
                    <Checkbox
                      checked={impactChecks.employee}
                      onChange={(v) =>
                        setImpactChecks((p) => ({ ...p, employee: v }))
                      }
                      onClick={(e) => e.stopPropagation()}
                    />
                    <span className='impact-block-header__icon'>
                      <UserIcon />
                    </span>
                    <span>{t('incidentReport:section.employeeImpacted')}</span>
                  </div>

                  <div className='addEmployee'>
                    <Button
                      type='text'
                      className='addEmployee-table__add'
                      icon={<IconPlus />}
                      onClick={(e) => {
                        e.stopPropagation()
                        addEmployeeRef.current?.(emptyEmployeeRow())
                      }}
                    >
                      {t('incidentReport:btn.addEmployee')}
                    </Button>
                  </div>
                </div>
                {impactChecks.employee && (
                  <div className='impact-block-content'>
                    <FormList
                      field='incidentReportDetailEmployeeSaveRequests'
                      rules={[
                        {
                          required: true,
                          type: 'array',
                          minLength: 1,
                          message: t('common:pleaseSelect'),
                        },
                      ]}
                    >
                      {(fields, { add, remove }) => {
                        addEmployeeRef.current = add
                        return (
                          <div className='incident-dynamic-table-wrap'>
                            <table className='incident-dynamic-table'>
                              <thead>
                                <tr>
                                  <th>
                                    <span className='ant-form-item-required'>
                                      *
                                    </span>
                                    {t('incidentReport:table.name')}
                                  </th>
                                  <th>
                                    {t('incidentReport:table.titleSynced')}
                                  </th>
                                  <th>
                                    <span className='ant-form-item-required'>
                                      *
                                    </span>
                                    {t('incidentReport:table.natureOfInjuryAr')}
                                  </th>
                                  <th>
                                    {t('incidentReport:table.natureOfInjuryEn')}
                                  </th>
                                  <th className='incident-dynamic-table__col-action' />
                                </tr>
                              </thead>
                              <tbody>
                                {fields.map((item, rowIndex) => (
                                  <tr key={item.key}>
                                    <td>
                                      <FormItem
                                        field={`${item.field}.userId`}
                                        className='incident-dynamic-table__cell-item'
                                        help={null}
                                        rules={[
                                          {
                                            required: true,
                                            message: t('common:pleaseSelect'),
                                          },
                                        ]}
                                      >
                                        <Select
                                          maxTagCount='responsive'
                                          placeholder={t('common:pleaseSelect')}
                                          options={userList}
                                          style={{ width: 150 }}
                                          allowClear
                                          showSearch
                                          filterOption={(inputValue, option) =>
                                            option?.props?.children
                                              .toLowerCase()
                                              .indexOf(
                                                inputValue.toLowerCase(),
                                              ) >= 0
                                          }
                                        />
                                      </FormItem>
                                    </td>
                                    <td>
                                      <FormItem
                                        field={`${item.field}.title`}
                                        noStyle
                                      >
                                        <Input
                                          placeholder={t(
                                            'incidentReport:form.autoFilled',
                                          )}
                                          className='incident-dynamic-table__readonly'
                                        />
                                      </FormItem>
                                    </td>
                                    <td>
                                      <FormItem
                                        field={`${item.field}.natureOfInjuryAr`}
                                        className='incident-dynamic-table__cell-item'
                                        help={null}
                                        rules={[
                                          {
                                            required: true,
                                            message: t('common:pleaseEnter'),
                                          },
                                        ]}
                                      >
                                        <Input
                                          placeholder={t('common:pleaseEnter')}
                                        />
                                      </FormItem>
                                    </td>
                                    <td>
                                      <FormItem
                                        field={`${item.field}.natureOfInjury`}
                                        className='incident-dynamic-table__cell-item'
                                        help={null}
                                        rules={[
                                          {
                                            required: false,
                                            message: t('common:pleaseEnter'),
                                          },
                                        ]}
                                      >
                                        <Input
                                          placeholder={t('common:pleaseEnter')}
                                        />
                                      </FormItem>
                                    </td>
                                    <td className='incident-dynamic-table__col-action'>
                                      <Button
                                        type='text'
                                        size='small'
                                        className='incident-dynamic-table__btn-delete'
                                        icon={<IconDelete />}
                                        onClick={() => remove(rowIndex)}
                                      />
                                    </td>
                                  </tr>
                                ))}
                              </tbody>
                            </table>
                          </div>
                        )
                      }}
                    </FormList>
                  </div>
                )}
              </div>

              {/* Property Impacted */}
              <div className='impact-block'>
                <div
                  className={classNames('impact-block-header', {
                    'impact-block-header--checked': impactChecks.property,
                  })}
                  onClick={() =>
                    setImpactChecks((p) => ({ ...p, property: !p.property }))
                  }
                >
                  <div className='employee-left'>
                    <Checkbox
                      checked={impactChecks.property}
                      onChange={(v) =>
                        setImpactChecks((p) => ({ ...p, property: v }))
                      }
                      onClick={(e) => e.stopPropagation()}
                    />
                    <span className='impact-block-header__icon'>
                      <PalaceIcon />
                    </span>
                    <span>{t('incidentReport:section.propertyImpacted')}</span>
                  </div>

                  <div className='addEmployee'>
                    <Button
                      type='text'
                      className='addEmployee-table__add'
                      icon={<IconPlus />}
                      onClick={(e) => {
                        e.stopPropagation()
                        addPropertyRef.current?.(emptyPropertyRow())
                      }}
                    >
                      {t('incidentReport:btn.addProperty')}
                    </Button>
                  </div>
                </div>
                {impactChecks.property && (
                  <div className='impact-block-content'>
                    <FormList
                      field='incidentReportDetailPropertySaveRequests'
                      rules={[
                        {
                          required: true,
                          type: 'array',
                          minLength: 1,
                          message: t('common:pleaseSelect'),
                        },
                      ]}
                    >
                      {(fields, { add, remove }) => {
                        addPropertyRef.current = add
                        return (
                        <div className='incident-dynamic-table-wrap'>
                          <table className='incident-dynamic-table'>
                            <thead>
                              <tr>
                                <th>
                                  <span className='ant-form-item-required'>
                                    *
                                  </span>
                                  {t('incidentReport:table.propertyType')}
                                </th>
                                <th>
                                  <span className='ant-form-item-required'>
                                    *
                                  </span>
                                  {t('incidentReport:table.propertyNameAr')}
                                </th>
                                <th>
                                  {t('incidentReport:table.propertyNameEn')}
                                </th>
                                <th>
                                  <span className='ant-form-item-required'>
                                    *
                                  </span>
                                  {t('incidentReport:table.natureOfDamageAr')}
                                </th>
                                <th>
                                  {t('incidentReport:table.natureOfDamageEn')}
                                </th>
                                <th className='incident-dynamic-table__col-action' />
                              </tr>
                            </thead>
                            <tbody>
                              {fields.map((item, rowIndex) => (
                                <tr key={item.key}>
                                  <td>
                                    <FormItem
                                      field={`${item.field}.propertyType`}
                                      className='incident-dynamic-table__cell-item'
                                      help={null}
                                      rules={[
                                        {
                                          // Required for new rows only; legacy rows
                                          // (with propertyImpactedId) may stay empty
                                          validator: (val, cb) => {
                                            const isLegacyRow = Boolean(
                                              form.getFieldValue(
                                                `${item.field}.propertyImpactedId`,
                                              ),
                                            )
                                            if (!isLegacyRow && val == null) {
                                              cb(t('common:pleaseSelect'))
                                            } else {
                                              cb()
                                            }
                                          },
                                        },
                                      ]}
                                    >
                                      <Select
                                        placeholder={t('common:pleaseSelect')}
                                        options={propertyTypeOptions}
                                        style={{ width: 180 }}
                                        allowClear
                                      />
                                    </FormItem>
                                  </td>
                                  <td>
                                    <FormItem
                                      field={`${item.field}.propertyNameAr`}
                                      className='incident-dynamic-table__cell-item'
                                      help={null}
                                      rules={[
                                        {
                                          required: true,
                                          message: t('common:pleaseEnter'),
                                        },
                                      ]}
                                    >
                                      <Input
                                        placeholder={t('common:pleaseEnter')}
                                      />
                                    </FormItem>
                                  </td>
                                  <td>
                                    <FormItem
                                      field={`${item.field}.propertyName`}
                                      className='incident-dynamic-table__cell-item'
                                      help={null}
                                      rules={[
                                        {
                                          required: false,
                                          message: t('common:pleaseEnter'),
                                        },
                                      ]}
                                    >
                                      <Input
                                        placeholder={t('common:pleaseEnter')}
                                      />
                                    </FormItem>
                                  </td>
                                  <td>
                                    <FormItem
                                      field={`${item.field}.natureOfDamageAr`}
                                      className='incident-dynamic-table__cell-item'
                                      help={null}
                                      rules={[
                                        {
                                          required: true,
                                          message: t('common:pleaseEnter'),
                                        },
                                      ]}
                                    >
                                      <Input
                                        placeholder={t('common:pleaseEnter')}
                                      />
                                    </FormItem>
                                  </td>
                                  <td>
                                    <FormItem
                                      field={`${item.field}.natureOfDamage`}
                                      className='incident-dynamic-table__cell-item'
                                      help={null}
                                      rules={[
                                        {
                                          required: false,
                                          message: t('common:pleaseEnter'),
                                        },
                                      ]}
                                    >
                                      <Input
                                        placeholder={t('common:pleaseEnter')}
                                      />
                                    </FormItem>
                                  </td>
                                  <td className='incident-dynamic-table__col-action'>
                                    <Button
                                      type='text'
                                      size='small'
                                      className='incident-dynamic-table__btn-delete'
                                      icon={<IconDelete />}
                                      onClick={() => remove(rowIndex)}
                                    />
                                  </td>
                                </tr>
                              ))}
                            </tbody>
                          </table>
                        </div>
                        )
                      }}
                    </FormList>
                  </div>
                )}
              </div>

              {/* Other Impact */}
              <div className='impact-block impact-block-other'>
                <div
                  className={classNames('impact-block-header', {
                    'impact-block-header--checked': impactChecks.other,
                  })}
                  onClick={() =>
                    setImpactChecks((p) => ({ ...p, other: !p.other }))
                  }
                >
                  <div className='employee-left'>
                    <Checkbox
                      checked={impactChecks.other}
                      onChange={(v) =>
                        setImpactChecks((p) => ({ ...p, other: v }))
                      }
                      onClick={(e) => e.stopPropagation()}
                    />
                    <span className='impact-block-header__icon'>
                      <MoreFourIcon />
                    </span>
                    <span>{t('incidentReport:section.otherImpact')}</span>
                  </div>
                </div>
                {impactChecks.other && (
                  <div className='impact-block-content'>
                    <Row gutter={24}>
                      <Col span={12}>
                        <FormItem
                          label={t('incidentReport:form.otherImpactAr')}
                          field='otherImpactAr'
                        >
                          <TextArea
                            placeholder={t('common:pleaseEnter')}
                            maxLength={500}
                            showWordLimit
                          />
                        </FormItem>
                      </Col>
                      <Col span={12}>
                        <FormItem
                          label={t('incidentReport:form.otherImpactEn')}
                          field='otherImpact'
                        >
                          <TextArea
                            placeholder={t('common:pleaseEnter')}
                            maxLength={500}
                            showWordLimit
                          />
                        </FormItem>
                      </Col>
                    </Row>
                  </div>
                )}
              </div>

              {/* ─── ISSUES IDENTIFIED ─── */}
              <div className='section-header'>
                <span>{t('incidentReport:section.issuesIdentified')}</span>
              </div>
              <FormList field='issues'>
                {(fields, { add, remove }) => (
                  <>
                    {fields.map((item, rowIndex) => (
                      <div key={item.key} className='issue-item'>
                        <div className='issue-item-header'>
                          <span className='issue-item-header__title'>
                            {t('incidentReport:issueLabel', {
                              num: rowIndex + 1,
                            })}
                          </span>
                          <Button
                            type='text'
                            size='small'
                            className='issue-item-header__delete'
                            icon={<IconDelete />}
                            onClick={() => remove(rowIndex)}
                          />
                        </div>
                        <Row gutter={24}>
                          <Col span={12}>
                            <FormItem
                              label={t('incidentReport:form.notesRemarksAr')}
                              field={`${item.field}.notesRemarksAr`}
                              rules={[
                                {
                                  required: true,
                                  message: t('common:pleaseEnter'),
                                },
                              ]}
                            >
                              <TextArea
                                placeholder={t('common:pleaseEnter')}
                                maxLength={500}
                                showWordLimit
                              />
                            </FormItem>
                          </Col>
                          <Col span={12}>
                            <FormItem
                              label={t('incidentReport:form.notesRemarksEn')}
                              field={`${item.field}.notesRemarksEn`}
                            >
                              <TextArea
                                placeholder={t('common:pleaseEnter')}
                                maxLength={500}
                                showWordLimit
                              />
                            </FormItem>
                          </Col>
                          <Col span={24}>
                            <FormItem
                              label={t('incidentReport:form.attachment')}
                              field={`${item.field}.attachmentList`}
                              initialValue={[]}
                            >
                              <IncidentAttachmentUpload />
                            </FormItem>
                          </Col>
                          <Col span={12}>
                            <FormItem
                              label={t(
                                'incidentReport:form.correctiveActionAr',
                              )}
                              field={`${item.field}.correctiveActionAr`}
                              rules={[
                                {
                                  required: true,
                                  message: t('common:pleaseEnter'),
                                },
                              ]}
                            >
                              <TextArea
                                placeholder={t('common:pleaseEnter')}
                                maxLength={500}
                                showWordLimit
                              />
                            </FormItem>
                          </Col>
                          <Col span={12}>
                            <FormItem
                              label={t(
                                'incidentReport:form.correctiveActionEn',
                              )}
                              field={`${item.field}.correctiveActionEn`}
                            >
                              <TextArea
                                placeholder={t('common:pleaseEnter')}
                                maxLength={500}
                                showWordLimit
                              />
                            </FormItem>
                          </Col>
                          <Col span={12}>
                            <FormItem
                              label={t(
                                'incidentReport:form.responsibleDepartment',
                              )}
                              field={`${item.field}.responsibleOrgId`}
                              rules={[
                                {
                                  required: true,
                                  message: t('common:pleaseEnter'),
                                },
                              ]}
                            >
                              <TreeSelect
                                treeData={orgData}
                                placeholder={t('common:pleaseSelect')}
                                allowClear
                                onClick={(e: React.MouseEvent) =>
                                  e.stopPropagation()
                                }
                              />
                            </FormItem>
                          </Col>
                          <Col span={12}>
                            <FormItem
                              label={t('incidentReport:form.targetClosureDate')}
                              field={`${item.field}.targetClosureDate`}
                              rules={[
                                {
                                  required: true,
                                  message: t('common:pleaseSelect'),
                                },
                              ]}
                            >
                              <DatePicker
                                format='DD/MM/YYYY'
                                style={{ width: '100%' }}
                              />
                            </FormItem>
                          </Col>
                        </Row>
                      </div>
                    ))}
                    <Button
                      type='text'
                      className='incident-dynamic-table__add issues-add-btn'
                      icon={<IconPlus />}
                      onClick={() => add(emptyIssueRow())}
                    >
                      {t('incidentReport:btn.addIssue')}
                    </Button>
                  </>
                )}
              </FormList>
            </Form>
          </div>

          <div className='addOrEdit-right'>
            <ApprovalProgressCard
              title={t('incidentReport:progress.title')}
              approvalRejected={incidentReportReject}
              approvalApproved={incidentReportApproval}
              approveLog={approveLog}
              approveFlag={current == 2 ? 0 : approveFlag}
              moduleId={id}
              moduleIdKey='incidentReportId'
            />
          </div>
        </div>

        <div className='addOrEdit-footer'>
          <Button
            className='addOrEdit-footer__btn'
            icon={<IconClose />}
            onClick={handelCancel}
          >
            {t('common:btn.cancel')}
          </Button>
          <Button
            className='addOrEdit-footer__btn'
            loading={saveOnlyLoading}
            onClick={handleSave}
          >
            {t('common:btn.save')}
          </Button>
          <Button
            type='primary'
            className='addOrEdit-footer__btn'
            icon={<IconUpload />}
            onClick={handelSubmit}
            loading={saveDetailLoading}
          >
            {t('common:btn.submit')}
          </Button>
        </div>
      </div>
    </Spin>
  )
}

