.incident-dynamic-table {
  width: 100%;
  border-collapse: separate;
  border-spacing: 0;
  border: 1px solid #e5e6eb;
  border-radius: 8px;
  overflow: hidden;
  background: #fff;
  // border: 1px solid red;

  thead tr {
    background: #f7f8fa;
  }

  th {
    padding: 10px 12px;
    text-align: left;
    font-weight: 500;
    font-size: 13px;
    color: #1d2129;
    border-bottom: 1px solid #e5e6eb;
    .ant-form-item-required {
      color: rgb(var(--danger-6));
      margin-right: 4px;
      font-size: 20px;
      line-height: 1;
      vertical-align: middle;
    }
  }

  td {
    padding: 8px 12px;
    vertical-align: middle;
    border-bottom: 1px solid #e5e6eb;
    background: #fff;

    .formblink-enter-done {
      display: none;
    }
  }

  /* 动态表格内字段垂直居中 */
  .incident-dynamic-table__cell-item {
    margin-bottom: 0;
    display: flex;

