        }
      }

      // ── Issue items ──
      .issue-item {
        border: 1px solid #e5e6eb;
        border-radius: 8px;
        padding: 16px;
        margin-bottom: 16px;
        background: #fff;
      }

      .issue-item-header {
        margin-bottom: 12px;

        &__title {
          font-weight: 700;
          font-size: 14px;
          text-transform: uppercase;
          color: #1d2129;
        }
      }
    }

    .incidentReportDetail-top-right {
      display: flex;
      flex: 0 0 388px;
      overflow-y: auto;
      min-height: 0;

      body[dir='ltr'] & {
        border-left: 1px solid #e5e6eb;
      }

      body[dir='rtl'] & {
        border-right: 1px solid #e5e6eb;
      }

      .approval-progress-card {
        width: 100%;
        height: 100%;
        display: flex;
        flex-direction: column;
      }

      .approval-progress-card__content {
        flex: 1;
      }
    }
  }

  .incidentReportDetail-bottom {
    position: sticky;
    bottom: 0;
    z-index: 10;
    flex-shrink: 0;
    display: flex;
    align-items: center;
    justify-content: flex-end;
    gap: 12px;
    padding: 16px 20px;
    background-color: #fff;
    border-top: 1px solid #e5e6eb;

    .footer__btn {
      min-width: 96px;
