import '../InspectionForm/style/index.less'
import './style/index.less'
import { useEffect, useMemo, useState } from 'react'
import { useTranslation } from 'react-i18next'
import { useNavigate, useParams } from 'react-router-dom'
import { useRequest } from 'ahooks'
import { Badge, Button, Space, Spin } from '@arco-design/web-react'
import {
  IconArrowLeft,
  IconEdit,
  IconFile,
} from '@arco-design/web-react/icon'
import BreadcrumbNav from '@common/Layout/components/BreadcrumbNav'
import PageWrapper from '@common/components/PageWrapper'
import ApprovalProgressCard from '@common/components/ApprovalProgressCard'
import classNames from 'classnames'
import {
  monthlyInspectionStatusColorArr,
  MonthlyInspectionStatusEnum,
  STATUS_CODE_TO_KEY,
} from '@/constants/monthlyInspection'
import {
  monthlyInspectionDetail,
  monthlyInspectionFindingCount,
  monthlyInspectionFormReject,
  monthlyInspectionFormApprove,
  monthlyInspectionFormApproveDetail,
} from '@/service/apis'
import type {
  FindingCountTabSummary,
  MonthlyInspectionStatus,
} from '@/types/MonthlyInspection'
import TopBar from '../InspectionForm/components/TopBar'
import LeftAnchor from '../InspectionForm/components/LeftAnchor'
import {
  useAnchorNodes,
  anchorKeyToDetailParams,
} from '../InspectionForm/floorData'
import { mapDetailToSections } from '../InspectionForm/shared'
import type { RightSectionVM } from '../InspectionForm/components/RightContent'
import ViewSectionCard from './components/ViewSectionCard'
import ExportReportModal from './components/ExportReportModal'
import { handelFieldNameShow } from '@/utils/tools'
import NoData from '@common/components/NoData'

const classPrefix = 'inspection-form-view'

const InspectionFormView = () => {
  const { t } = useTranslation(['monthlyInspection', 'common'])
  const { inspectionId, status: statusParam } = useParams<{
    inspectionId: string
    status: string
  }>()
  const status: MonthlyInspectionStatus =
    (statusParam as MonthlyInspectionStatus) ?? 'approved'

  const [activeAnchor, setActiveAnchor] = useState<string>('around')

  const [headerMeta, setHeaderMeta] = useState<{
    code: string
    inspectionDate: string
    inspector: string
    startTime?: string | null
    completeTime?: string | null
    duration?: string | null
  }>({ code: '', inspectionDate: '', inspector: '' })

  const [sections, setSections] = useState<RightSectionVM[]>([])
  const [findingSummary, setFindingSummary] = useState<
    FindingCountTabSummary[]
  >([])

  const [approveLog, setApproveLog] = useState<any>([])
  const [approveFlag, setApproveFlag] = useState<number>(0)
  const backUrl = `/monthly-inspection/list`
  const navigate = useNavigate()

  const { loading: fetchDetailLoading, run: fetchDetail } = useRequest(
    monthlyInspectionDetail,
    {
      manual: true,
      onSuccess: (res) => {
        if (!res) {
          setSections([])
          return
        }
        setHeaderMeta({
          code: res.code ?? '',
          inspectionDate: res.inspectionDate ?? '',
          inspector: (res.inspectorList ?? [])
            .map((item) =>
              handelFieldNameShow(
                item.inspectorName ?? '',
                item.inspectorNameAr ?? '',
              ),
            )
            .filter(Boolean)
            .join(', '),
          startTime: res.inspectionStartTime,
          completeTime: res.inspectionCompleteTime,
          duration:
            res.durationDays != null &&
            res.durationHours != null &&
            res.durationMinutes != null
              ? t('monthlyInspection:submitModal.durationValue', {
                  days: res.durationDays,
                  hours: res.durationHours,
                  minutes: res.durationMinutes,
                })
              : null,
        })
        setSections(mapDetailToSections(res))
        if (+status !== MonthlyInspectionStatusEnum.Draft) {
          runGetApproveDetail({ inspectionId })
        }
      },
    },
  )

  const { run: fetchFindingCount } = useRequest(monthlyInspectionFindingCount, {
    manual: true,
    onSuccess: (res) => {
      setFindingSummary(res ?? [])
    },
  })

  const { runAsync: runGetApproveDetail } = useRequest(
    monthlyInspectionFormApproveDetail,
    {
      manual: true,
      onSuccess: (res: any) => {
        const recordList = res?.approveList || []
        setApproveLog(recordList)
        setApproveFlag(res?.approveFlag)
      },
    })

  useEffect(() => {
    if (inspectionId == null) return
    const { type, floor } = anchorKeyToDetailParams(activeAnchor)
    fetchDetail({ inspectionId, type, floor })
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [inspectionId, activeAnchor])

  useEffect(() => {
    if (inspectionId == null) return
    fetchFindingCount({ inspectionId })
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [inspectionId])

  const breadcrumbList = useMemo(
    () => [
      {
        path: '/monthly-inspection/list',
        breadcrumbName: t('monthlyInspection:title'),
      },
      { path: '#', breadcrumbName: t('monthlyInspection:form.title') },
    ],
    [t],
  )

  const anchorNodes = useAnchorNodes(findingSummary)

  const activeLabel = useMemo(() => {
    for (const n of anchorNodes) {
      if (n.key === activeAnchor) return n.label
      const child = n.children?.find((c) => c.key === activeAnchor)
      if (child) return `${n.label} - ${child.label.replace(/^Floor /, '')}`
    }
    return ''
  }, [anchorNodes, activeAnchor])

  const inspectionFormTitle = () => {
    return (
      <div className={`${classPrefix}-header`}>
        <div className={`${classPrefix}-header-left`}>
          {t('monthlyInspection:form.title')}
        </div>
        <div className={`${classPrefix}-header-right`}>
          <Badge
            className={classNames({
              [`${classPrefix}-header-right-point`]: true,
              [`color-${status}`]: true,
            })}
            color={monthlyInspectionStatusColorArr[status]}
            text={t(`monthlyInspection:status.${STATUS_CODE_TO_KEY[status]}`)}
          />
        </div>
      </div>
    )
  }

  const handleCancel = () => {
    navigate('/monthly-inspection/list')
  }
  const handleEditForm = () => {
    navigate(`/monthly-inspection/inspection-form/${inspectionId}/3`)
  }

  const [exportModalVisible, setExportModalVisible] = useState(false)
  const handleExportView = () => {
    setExportModalVisible(true)
  }

  return (
    <>
      <BreadcrumbNav routes={breadcrumbList} />
      <PageWrapper
        resetMarginTop={true}
        headerTitle={inspectionFormTitle()}
        pageClassName={`${classPrefix}-page inspection-form-page`}
      >
        <div className={`${classPrefix} inspection-form`}>
          <TopBar
            code={headerMeta.code}
            inspectionDate={headerMeta.inspectionDate}
            inspector={headerMeta.inspector}
            startTime={headerMeta.startTime}
            completeTime={headerMeta.completeTime}
            duration={headerMeta.duration}
            showTimes={+status !== MonthlyInspectionStatusEnum.Draft}
          />

          <div className='inspection-form__body'>
            <div className='inspection-form__body-left'>
              <LeftAnchor
                nodes={anchorNodes}
                activeKey={activeAnchor}
                onChange={setActiveAnchor}
                hideStatusIcon
              />
            </div>

            <div className='inspection-form__body-right'>
              <Spin
                loading={fetchDetailLoading}
                block
                className={`${classPrefix}__spin`}
              >
                <div className={`${classPrefix}__group-title`}>
                  {activeLabel}
                </div>
                <div className={`${classPrefix}__sections`}>
                  {!fetchDetailLoading &&
                    (sections.length > 0 ? (
                      sections.map((sec, idx) => (
                        <ViewSectionCard
                          key={sec.id}
                          section={sec}
                          index={idx}
                        />
                      ))
                    ) : (
                      <NoData />
                    ))}
                </div>
              </Spin>
            </div>

            <div className={`${classPrefix}__side`}>
              <ApprovalProgressCard
                title={t('monthlyInspection:form.inspectionApproval')}
                approvalRejected={monthlyInspectionFormReject}
                approvalApproved={monthlyInspectionFormApprove}
                approveLog={approveLog}
                approveFlag={approveFlag}
                backUrl={backUrl}
                moduleId={inspectionId}
                moduleIdKey='inspectionId'
              />
            </div>
          </div>
        </div>
        {+status !== MonthlyInspectionStatusEnum.UnderReview && (
          <div className='inspection-form__footer'>
            <Space size={12} className={`${classPrefix}__footer-right`}>
              <Button icon={<IconArrowLeft />} onClick={handleCancel}>
                {t('common:btn.back')}
              </Button>

              {+status === MonthlyInspectionStatusEnum.Approved && (
                <Button
                  type='primary'
                  icon={<IconFile />}
                  onClick={handleExportView}
                >
                  {t('common:btn.viewReport')}
                </Button>
              )}

              {+status === MonthlyInspectionStatusEnum.Rejected && (
                <Button
                  type='primary'
                  icon={<IconEdit />}
                  onClick={handleEditForm}
                >
                  {t('common:btn.edit')}
                </Button>
              )}
            </Space>
          </div>
        )}

        <ExportReportModal
          visible={exportModalVisible}
          onCancel={() => setExportModalVisible(false)}
        />
      </PageWrapper>
    </>
  )
}

export default InspectionFormView

