import { IconDown, IconUp } from '@arco-design/web-react/icon'
import type { UploadItem } from '@arco-design/web-react/es/Upload/interface'
import { handelFieldNameShow } from '@/utils/tools'
import type { DetailCorrectiveActionOrg } from '@/types/MonthlyInspection'

const classPrefix = 'view-section-card'

export type ViewAnswer = 'yes' | 'no' | null

export interface ViewFindingVM {
  id: string
  notesAr: string
  notesEn: string
  attachments: UploadItem[]
  correctiveActionAr: string
  correctiveActionEn: string
  dept?: string
  org?: DetailCorrectiveActionOrg
  targetClosureDate?: string
}

export interface ViewQuestionVM {
  id: string
  question: string
  answer: ViewAnswer
  findings: ViewFindingVM[]
}

export interface ViewSectionVM {
  id: string
  title: string
  defaultOpen?: boolean
  questions: ViewQuestionVM[]
}

/* ---------- single answer pill (only the chosen side is rendered) ---------- */
const AnswerPill = ({ value }: { value: ViewAnswer }) => {
  const { t } = useTranslation(['common'])
  if (value !== 'yes' && value !== 'no') return null
  return (
    <span
      className={classNames(`${classPrefix}__pill`, {
        [`${classPrefix}__pill--yes`]: value === 'yes',
        [`${classPrefix}__pill--no`]: value === 'no',
      })}
    >
      {value === 'yes' ? t('common:yes') : t('common:no')}
    </span>
  )
}

/* ---------- one labeled read-only field ---------- */
const Field = ({ label, value }: { label: string; value: string }) => (
  <div className={`${classPrefix}__field`}>
    <div className={`${classPrefix}__field-label`}>{label}</div>
    <div className={`${classPrefix}__field-value`}>{value || '-'}</div>
  </div>
)

/* ---------- one finding block inside the shared gray container ---------- */
const FindingBlock = ({
  finding,
  index,
}: {
  finding: ViewFindingVM
  index: number
}) => {
  const { t } = useTranslation(['monthlyInspection', 'common'])
  const notes = handelFieldNameShow(finding.notesEn, finding.notesAr)
  const ca = handelFieldNameShow(
    finding.correctiveActionEn,
    finding.correctiveActionAr,
  )
  return (
    <div
      className={classNames(`${classPrefix}__finding`, {
        [`${classPrefix}__finding--has-divider`]: index > 0,
      })}
    >
      <div className={`${classPrefix}__finding-title`}>
        {t('monthlyInspection:form.finding', { n: index + 1 })}
      </div>

      <Field label={t('monthlyInspection:form.notes')} value={notes} />

      <div className={`${classPrefix}__field`}>
        <div className={`${classPrefix}__field-label`}>
          {t('monthlyInspection:form.attachment')}
        </div>
        {finding.attachments.length > 0 ? (
          <Upload
            listType='picture-card'
            imagePreview
            fileList={finding.attachments}
            showUploadList={{ removeIcon: null }}
            disabled
          >
            {null}
          </Upload>
        ) : (
          <div className={`${classPrefix}__field-value`}>-</div>
        )}
      </div>

      <Field
        label={t('monthlyInspection:correctiveActions.title')}
        value={ca}
      />

      <div className={`${classPrefix}__finding-row`}>
        <Field
          label={t('monthlyInspection:form.responsibleDepartment')}
          value={
            finding.org
              ? handelFieldNameShow(
                  finding.org.orgName,
                  finding.org.orgNameAr,
                )
              : ''
          }
        />
        <Field
          label={t('monthlyInspection:form.targetClosureDate')}
          value={finding.targetClosureDate ?? ''}
        />
      </div>
    </div>
  )
}

/* ---------- one question row (text + pill, optional findings drawer) ---------- */
const ViewQuestion = ({ question }: { question: ViewQuestionVM }) => {
  const showFindings =
    question.answer === 'no' && (question.findings?.length ?? 0) > 0
  return (
    <div className={`${classPrefix}__question`}>
      <div className={`${classPrefix}__question-row`}>
        <div className={`${classPrefix}__question-text`}>
          {question.question}
        </div>
        <AnswerPill value={question.answer} />
      </div>
      {showFindings && (
        <div className={`${classPrefix}__findings`}>
          {question.findings.map((f, idx) => (
            <FindingBlock key={f.id} finding={f} index={idx} />
          ))}
        </div>
      )}
    </div>
  )
}

/* ---------- ViewSectionCard ---------- */
interface ViewSectionCardProps {
  section: ViewSectionVM
  index: number
}

const ViewSectionCard = ({ section, index }: ViewSectionCardProps) => {
  const { t } = useTranslation(['monthlyInspection'])
  const [open, setOpen] = useState(section.defaultOpen !== false)
  return (
    <div className={`${classPrefix}`}>
      <div
        className={`${classPrefix}__header`}
        onClick={() => setOpen((v) => !v)}
      >
        <div className={`${classPrefix}__head-text`}>
          <div className={`${classPrefix}__category`}>
            {t('monthlyInspection:form.section', { n: index + 1 })}
          </div>
          <div className={`${classPrefix}__title`}>{section.title}</div>
        </div>
        {open ? <IconUp /> : <IconDown />}
      </div>
      {open && section.questions.length > 0 && (
        <div className={`${classPrefix}__body`}>
          {section.questions.map((q, i, arr) => (
            <div
              key={q.id}
              className={classNames(`${classPrefix}__item`, {
                [`${classPrefix}__item--last`]: i === arr.length - 1,
              })}
            >
              <ViewQuestion question={q} />
            </div>
          ))}
        </div>
      )}
    </div>
  )
}

export default ViewSectionCard

