import './index.less'
import { useState } from 'react'
import { useTranslation } from 'react-i18next'
import {
  Button,
  DatePicker,
  Form,
  Input,
  Message,
  TreeSelect,
  Upload,
} from '@arco-design/web-react'
import type { FormInstance } from '@arco-design/web-react'
import type { UploadItem } from '@arco-design/web-react/es/Upload/interface'
import type { TransformedOrgNode } from '@/utils/tools'
import type { DetailCorrectiveActionOrg } from '@/types/MonthlyInspection'
import {
  IconCheckCircle,
  IconDelete,
  IconDown,
  IconLoading,
  IconPlus,
  IconUp,
} from '@arco-design/web-react/icon'
import {
  ATTACHMENT_ACCEPT_TYPES,
  ATTACHMENT_MAX_COUNT,
  ATTACHMENT_MAX_SIZE,
  handleUploadRequest,
} from '../../shared'

const classPrefix = 'inspection-form-right'
const NOTES_MAX = 500

export type AnswerValue = 'yes' | 'no' | null

export interface RightFindingVM {
  id: string
  notesAr: string
  notesEn: string
  attachments: UploadItem[]
  correctiveActionAr: string
  correctiveActionEn: string
  dept?: string
  org?: DetailCorrectiveActionOrg
  targetClosureDate?: string
}

export interface RightQuestionVM {
  id: string
  itemId: string
  question: string
  answer: AnswerValue
  findings: RightFindingVM[]
  defaultDept?: string
}

export interface RightSectionVM {
  id: string
  title: string
  defaultOpen?: boolean
  questions: RightQuestionVM[]
}

interface RightContentProps {
  form: FormInstance
  sectionGroupTitle: string
  groupTip?: string
  checkActionLabel?: string
  checkActionLoading?: boolean
  onCheckAction?: () => void
  sections: RightSectionVM[]
  deptOptions?: TransformedOrgNode[]
  onAnswerChange?: (
    sectionId: string,
    questionId: string,
    v: AnswerValue,
  ) => void
  onAddFinding?: (sectionId: string, questionId: string) => void
  onRemoveFinding?: (
    sectionId: string,
    questionId: string,
    findingId: string,
  ) => void
  onValuesChange?: (changedValues: unknown, allValues: unknown) => void
}

const fieldOf = (findingId: string, key: keyof RightFindingVM) =>
  `findings.${findingId}.${key}`

const useBeforeAttachmentUpload = () => {
  const { t } = useTranslation(['monthlyInspection'])
  return (file: File) => {
    if (!ATTACHMENT_ACCEPT_TYPES.includes(file.type)) {
      Message.error(t('monthlyInspection:form.attachmentTip'))
      return false
    }
    if (file.size > ATTACHMENT_MAX_SIZE) {
      Message.error(t('monthlyInspection:form.attachmentTip'))
      return false
    }
    return true
  }
}

/* ---------- Yes/No ---------- */
const YesNo = ({
  value,
  onChange,
}: {
  value: AnswerValue
  onChange?: (v: AnswerValue) => void
}) => {
  const { t } = useTranslation(['common'])
  return (
    <div className={`${classPrefix}__yesno`}>
      <button
        type='button'
        className={`${classPrefix}__yesno-btn ${
          value === 'yes' ? `${classPrefix}__yesno-btn--yes-active` : ''
        }`}
        onClick={() => onChange?.('yes')}
      >
        {t('common:yes')}
      </button>
      <button
        type='button'
        className={`${classPrefix}__yesno-btn ${
          value === 'no' ? `${classPrefix}__yesno-btn--no-active` : ''
        }`}
        onClick={() => onChange?.('no')}
      >
        {t('common:no')}
      </button>
    </div>
  )
}

/* ---------- FindingCard (form-driven) ---------- */
const FindingCard = ({
  finding,
  index,
  total,
  onRemove,
  deptOptions,
}: {
  finding: RightFindingVM
  index: number
  total: number
  onRemove?: () => void
  deptOptions?: TransformedOrgNode[]
}) => {
  const { t } = useTranslation(['monthlyInspection', 'common'])
  const beforeAttachmentUpload = useBeforeAttachmentUpload()
  const canRemove = total > 1
  return (
    <div className={`${classPrefix}__finding${index > 0 ? ' mt20' : ''}`}>
      <div className={`${classPrefix}__finding-head`}>
        <div className={`${classPrefix}__finding-title`}>
          {t('monthlyInspection:form.finding', { n: index + 1 })}
        </div>
        <Button
          type='text'
          size='mini'
          status={canRemove ? 'danger' : 'default'}
          icon={<IconDelete />}
          style={canRemove ? undefined : { color: '#c9cdd4' }}
          onClick={canRemove ? onRemove : undefined}
        />
      </div>

      <div className={`${classPrefix}__finding-body`}>
        <div className={`${classPrefix}__notes-block`}>
          <Form.Item
            label={t('monthlyInspection:form.notesAr')}
            field={fieldOf(finding.id, 'notesAr')}
            rules={[{ required: true, message: t('common:pleaseEnter') }]}
          >
            <Input.TextArea
              className={`${classPrefix}__notes-textarea rtl-input`}
              placeholder={t('common:pleaseEnter')}
              maxLength={NOTES_MAX}
              showWordLimit
              autoSize={{ minRows: 2 }}
            />
          </Form.Item>
        </div>

        <div className={`${classPrefix}__notes-block`}>
          <Form.Item
            label={t('monthlyInspection:form.notesEn')}
            field={fieldOf(finding.id, 'notesEn')}
          >
            <Input.TextArea
              className={`${classPrefix}__notes-textarea`}
              placeholder={t('common:pleaseEnter')}
              maxLength={NOTES_MAX}
              showWordLimit
              autoSize={{ minRows: 2 }}
            />
          </Form.Item>
        </div>

        <div className={`${classPrefix}__attachment-block`}>
          <div className={`${classPrefix}__attachment-tip`}>
            {t('monthlyInspection:form.attachmentTip')}
          </div>
          <Form.Item
            label={t('monthlyInspection:form.attachment')}
            field={fieldOf(finding.id, 'attachments')}
            rules={[
              {
                required: true,
                validator: (
                  val: UploadItem[] | undefined,
                  cb: (error?: string) => void,
                ) => {
                  const list = val ?? []
                  const uploading = list.some(
                    (f) => f.status === 'uploading' || f.status === 'init',
                  )
                  if (uploading) {
                    cb()
                    return
                  }
                  const done = list.filter(
                    (f) => f.status === 'done' || !f.status,
                  )
                  if (done.length === 0) {
                    cb(t('monthlyInspection:form.attachmentRequired'))
                  } else {
                    cb()
                  }
                },
              },
            ]}
            triggerPropName='fileList'
          >
            <Upload
              listType='picture-card'
              imagePreview
              multiple
              limit={ATTACHMENT_MAX_COUNT}
              accept='.png,.jpg'
              beforeUpload={beforeAttachmentUpload}
              customRequest={handleUploadRequest}
              showUploadList={{ cancelIcon: <IconLoading />, startIcon: null }}
            >
              <div className={`${classPrefix}__upload-trigger`}>
                <IconPlus />
                <span>{t('common:upload')}</span>
              </div>
            </Upload>
          </Form.Item>
        </div>

        <div className={`${classPrefix}__notes-block`}>
          <Form.Item
            label={t('monthlyInspection:form.correctiveActionAr')}
            field={fieldOf(finding.id, 'correctiveActionAr')}
            rules={[{ required: true, message: t('common:pleaseEnter') }]}
          >
            <Input.TextArea
              className={`${classPrefix}__notes-textarea rtl-input`}
              placeholder={t('common:pleaseEnter')}
              maxLength={NOTES_MAX}
              showWordLimit
              autoSize={{ minRows: 2 }}
            />
          </Form.Item>
        </div>

        <div className={`${classPrefix}__notes-block`}>
          <Form.Item
            label={t('monthlyInspection:form.correctiveActionEn')}
            field={fieldOf(finding.id, 'correctiveActionEn')}
          >
            <Input.TextArea
              className={`${classPrefix}__notes-textarea`}
              placeholder={t('common:pleaseEnter')}
              maxLength={NOTES_MAX}
              showWordLimit
              autoSize={{ minRows: 2 }}
            />
          </Form.Item>
        </div>

        <div className={`${classPrefix}__finding-row`}>
          <Form.Item
            label={t('monthlyInspection:form.responsibleDepartment')}
            field={fieldOf(finding.id, 'dept')}
            rules={[{ required: true, message: t('common:pleaseSelect') }]}
          >
            <TreeSelect
              placeholder={t('common:pleaseSelect')}
              treeData={deptOptions ?? []}
              allowClear
            />
          </Form.Item>
          <Form.Item
            label={t('monthlyInspection:form.targetClosureDate')}
            field={fieldOf(finding.id, 'targetClosureDate')}
            rules={[{ required: true, message: t('common:pleaseSelect') }]}
          >
            <DatePicker
              placeholder={t('monthlyInspection:createModal.datePlaceholder')}
              style={{ width: '100%' }}
              format='DD/MM/YYYY'
            />
          </Form.Item>
        </div>
      </div>
    </div>
  )
}

/* ---------- Question ---------- */
const QuestionCard = ({
  sectionId,
  question,
  onAnswerChange,
  onAddFinding,
  onRemoveFinding,
  deptOptions,
}: {
  sectionId: string
  question: RightQuestionVM
  onAnswerChange?: RightContentProps['onAnswerChange']
  onAddFinding?: RightContentProps['onAddFinding']
  onRemoveFinding?: RightContentProps['onRemoveFinding']
  deptOptions?: TransformedOrgNode[]
}) => {
  const { t } = useTranslation(['monthlyInspection'])
  const requireDetails = question.answer === 'no'
  return (
    <div className={`${classPrefix}__question`}>
      <div className={`${classPrefix}__question-text`}>{question.question}</div>
      <YesNo
        value={question.answer}
        onChange={(v) => onAnswerChange?.(sectionId, question.id, v)}
      />
      {requireDetails && (
        <div className={`${classPrefix}__findings`}>
          {question.findings.map((f, idx) => (
            <FindingCard
              key={f.id}
              finding={f}
              index={idx}
              total={question.findings.length}
              deptOptions={deptOptions}
              onRemove={() => onRemoveFinding?.(sectionId, question.id, f.id)}
            />
          ))}
          <div className='add-btn-box'>
            <Button
              type='outline'
              long
              icon={<IconPlus />}
              className={`${classPrefix}__add-finding`}
              onClick={() => onAddFinding?.(sectionId, question.id)}
            >
              {t('monthlyInspection:form.addFinding')}
            </Button>
          </div>
        </div>
      )}
    </div>
  )
}

/* ---------- Section ---------- */
const SectionCard = ({
  section,
  index,
  deptOptions,
  onAnswerChange,
  onAddFinding,
  onRemoveFinding,
}: {
  section: RightSectionVM
  index: number
  deptOptions?: TransformedOrgNode[]
  onAnswerChange?: RightContentProps['onAnswerChange']
  onAddFinding?: RightContentProps['onAddFinding']
  onRemoveFinding?: RightContentProps['onRemoveFinding']
}) => {
  const { t } = useTranslation(['monthlyInspection'])
  const [open, setOpen] = useState(false)
  return (
    <div className={`${classPrefix}__section`}>
      <div
        className={`${classPrefix}__section-header`}
        onClick={() => setOpen((v) => !v)}
      >
        <div className={`${classPrefix}__section-head-text`}>
          <div className={`${classPrefix}__section-no`}>
            {t('monthlyInspection:form.section', { n: index + 1 })}
          </div>
          <div className={`${classPrefix}__section-title`}>{section.title}</div>
        </div>
        {open ? <IconUp /> : <IconDown />}
      </div>
      {open && section.questions.length > 0 && (
        <div className={`${classPrefix}__section-body`}>
          {section.questions.map((q, qIdx) => (
            <div
              key={q.id}
              className={`${classPrefix}__section-item${
                qIdx === section.questions.length - 1
                  ? ` ${classPrefix}__section-item--last`
                  : ''
              }`}
            >
              <QuestionCard
                sectionId={section.id}
                question={q}
                deptOptions={deptOptions}
                onAnswerChange={onAnswerChange}
                onAddFinding={onAddFinding}
                onRemoveFinding={onRemoveFinding}
              />
            </div>
          ))}
        </div>
      )}
    </div>
  )
}

/* ---------- RightContent (form root) ---------- */
const RightContent = ({
  form,
  sectionGroupTitle,
  groupTip,
  checkActionLabel,
  checkActionLoading,
  onCheckAction,
  sections,
  deptOptions,
  onAnswerChange,
  onAddFinding,
  onRemoveFinding,
  onValuesChange,
}: RightContentProps) => {
  const { t } = useTranslation(['monthlyInspection'])

  // Build initial values from sections, keyed by finding id.
  const initialValues = sections.reduce<{ findings: Record<string, unknown> }>(
    (acc, sec) => {
      sec.questions.forEach((q) => {
        q.findings.forEach((f) => {
          acc.findings[f.id] = {
            notesAr: f.notesAr,
            notesEn: f.notesEn,
            attachments: f.attachments,
            correctiveActionAr: f.correctiveActionAr,
            correctiveActionEn: f.correctiveActionEn,
            dept: f.dept,
            targetClosureDate: f.targetClosureDate,
          }
        })
      })
      return acc
    },
    { findings: {} },
  )

  return (
    <div className={classPrefix}>
      <div className={`${classPrefix}__header`}>
        <div className={`${classPrefix}__header-text`}>
          <div className={`${classPrefix}__group-title`}>
            {sectionGroupTitle}
          </div>
          {(groupTip ?? t('monthlyInspection:form.floorFinishedTip')) && (
            <div className={`${classPrefix}__group-tip`}>
              {groupTip ?? t('monthlyInspection:form.floorFinishedTip')}
            </div>
          )}
        </div>
        <Button
          type='primary'
          icon={<IconCheckCircle />}
          loading={checkActionLoading}
          className={`${classPrefix}__check-btn`}
          onClick={onCheckAction}
        >
          {checkActionLabel ?? t('monthlyInspection:form.checkAndSave')}
        </Button>
      </div>

      <Form
        form={form}
        layout='vertical'
        initialValues={initialValues}
        onValuesChange={onValuesChange}
        className={`${classPrefix}__form`}
      >
        <div className={`${classPrefix}__sections`}>
          {sections.map((sec, idx) => (
            <SectionCard
              key={sec.id}
              section={sec}
              index={idx}
              deptOptions={deptOptions}
              onAnswerChange={onAnswerChange}
              onAddFinding={onAddFinding}
              onRemoveFinding={onRemoveFinding}
            />
          ))}
        </div>
      </Form>
    </div>
  )
}

export default RightContent
